class Solution {
public:
    Solution(vector<int>& w) {
        for (int i = 1; i < w.size(); ++i) {
            w[i] += w[i - 1];
        }
        weights = w;
    }

    int pickIndex() {
        int target = rand() % weights.back() + 1;
        int left = 0, right = weights.size() - 1;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (weights[mid] < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
private:
    vector<int> weights;
};
